Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass TestContext.CancellationToken so the timeout is enforced
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new FakeHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    // Minimal fake handler — avoids external mocking libraries
    private sealed class FakeHttpMessageHandler(string content, HttpStatusCode statusCode)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();

            var response = new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Async tests | `async Task` return type — MSTest awaits natively |
| Timeouts | `[Timeout(5000)]` + `_testContext.CancellationToken` |
| Cancellation | Pre-cancelled `CancellationTokenSource` + `Assert.ThrowsExactlyAsync` |
| Sealed class | Performance & design clarity |
| Constructor injection | `TestContext` via constructor (MSTest 3.6+) |
| Exception testing | `ThrowsExactlyAsync` instead of `[ExpectedException]` |

The `[Timeout]` attribute fires `TestContext.CancellationToken` when time expires, so always pass that token through to your async calls under test.
